o-label{white-space:nowrap}.cssChoicebtn .nx-radio-faux{display:none!important}.cssRS10cols{width:100%;font-family:Arial,sans-serif;font-size:13px}.cssRS10cols .nx-repeating-section-header{display:grid;grid-template-columns:110px 130px 60px 110px 130px 60px 110px 140px 140px 260px;background:#f4f4f4;font-weight:600;border:1px solid #cfcfcf}.cssRS10cols .nx-repeating-section-row{display:grid;grid-template-columns:110px 130px 60px 110px 130px 60px 110px 140px 140px 260px;border-left:1px solid #cfcfcf;border-right:1px solid #cfcfcf}.cssRS10cols .nx-repeating-section-row>div,.cssRS10cols .nx-repeating-section-header>div{padding:6px 8px;border-bottom:1px solid #cfcfcf;display:flex;align-items:center}.cssRS10cols input[type="text"],.cssRS10cols input[type="number"]{text-align:right;width:100%}.cssRS10cols .rs-col-label{font-weight:600;white-space:nowrap}.cssRS10cols .rs-col-notes{font-size:13px;line-height:1.4;align-items:flex-start}.cssRS10cols .rs-total-row{font-weight:600;background:#f9f9f9;border-bottom:1px solid #cfcfcf}.cssRS10cols .nx-control-container{margin:0;padding:0}.grp-goodwill-detail .row:nth-child(1),.grp-goodwill-detail .row:nth-child(2),.grp-goodwill-detail .row:nth-child(5),.grp-goodwill-detail .row:nth-child(6),.grp-goodwill-detail .row:nth-child(9),.grp-goodwill-detail .row:nth-child(10){background-color:lightgray}.grp-goodwill-detail .row:nth-child(2),.grp-goodwill-detail .row:nth-child(4),.grp-goodwill-detail .row:nth-child(6),.grp-goodwill-detail .row:nth-child(8),.grp-goodwill-detail .row:nth-child(10),.grp-goodwill-detail .row:nth-child(12){border-bottom:1px solid #000}.grp-goodwill-detail .row:nth-child(3),.grp-goodwill-detail .row:nth-child(4),.grp-goodwill-detail .row:nth-child(7),.grp-goodwill-detail .row:nth-child(8),.grp-goodwill-detail .row:nth-child(11),.grp-goodwill-detail .row:nth-child(12){background-color:#F5F5F5}.grp-goodwill-detail .ntx-repeating-section-remove-button,.grp-goodwill-detail .btn-repeating-section-new-row{display:none!important}.grp-goodwill-detail+.btn-repeating-section-new-row{display:none!important}.nf-orange{background-color:#ff8c00!important;border:1px solid #e67e00!important;box-shadow:0 2px 4px rgb(0 0 0 / .15);border-radius:4px;color:#000000!important;padding:8px 12px}.nf-green{background-color:#28a745!important;border:1px solid #218838!important;box-shadow:0 2px 4px rgb(0 0 0 / .15);border-radius:4px;color:#ffffff!important;padding:8px 12px}.nf-red{background-color:#dc3545!important;border:1px solid #c82333!important;box-shadow:0 2px 4px rgb(0 0 0 / .15);border-radius:4px;color:#ffffff!important;padding:8px 12px}.nf-bg-grey{background-color:#d3d3d3;padding:10px}.repeatedGoodwillDetails .row>*{padding-right:calc(var(--bs-gutter-x) * 0.1);padding-left:calc(var(--bs-gutter-x) * 0.1)}.repeatedGoodwillDetails .nx-form .form-group{padding-top:.1rem;padding-bottom:.1rem}.repeatedGoodwillDetails form{padding:0 5px 10px}.repeatedGoodwillDetails+button.btn-repeating-section-new-row,.repeatedGoodwillDetails .ntx-repeating-section-remove-button{display:none}@media screen and (min-width:0){.nx-form{width:100%;padding:20px 15px}}@media screen and (min-width:768px){.nx-form{width:100%;padding:20px 15px}}@media screen and (min-width:940px){.nx-form{width:900px;padding:20px 15px}}@media screen and (min-width:1280px){.nx-form{width:1200px;padding:25px 15px;max-width:1200px}}

.repeatedGoodwillDetails form > div:not(:first-child) > div:nth-last-of-type(-n+2) {
    flex: 0 0 auto;
    width: 11.666667%;
    border-top: 0;
    border-bottom: 0;
}
.repeatedGoodwillDetails form > div:not(:first-child) > div:nth-child(1) {
    flex: 0 0 auto;
    width: 5.666667%;
}
.repeatedGoodwillDetails form > div:nth-child(3) > div:nth-child(1) {
    width: 15.666667%;
    flex: 0 0 auto;
}
.repeatedGoodwillDetails form > div:nth-child(2) > div:nth-child(1) {
    width: 5.666667%;
    flex: 0 0 auto;
}
.repeatedGoodwillDetails form > div:nth-child(n+4) > div:nth-child(n+2):nth-child(-n+8) {
    flex: 1 0 auto;
    width: 10.1%;
}
.repeatedGoodwillDetails form input {
    padding: .4375rem 0.35rem;
}
.repeatedGoodwillDetails form > div:nth-child(2) > div:nth-child(2),
.repeatedGoodwillDetails form > div:nth-child(2) > div:nth-child(4) {
    flex: 0 0 auto;
    width: 10%;
}
.repeatedGoodwillDetails form > div:nth-child(2) > div:nth-child(3),
.repeatedGoodwillDetails form > div:nth-child(2) > div:nth-child(5) {
    flex: 0 0 auto;
    width: 20.3%;
}
.repeatedGoodwillDetails form div:not(:first-of-type)>div {
    border: 1px solid #aeaeae;
}
